async function main() {
  console.log(`Seeding ${COMPANIES.length} DE companies...`);
  let created = 0, updated = 0;

  for (const entry of COMPANIES) {
    const slug = slugify(entry.name);

    const company = await prisma.company.upsert({
      where: { slug_market: { slug, market: Market.DE } },
      update: { name: entry.name, sector: entry.sector, websiteUrl: entry.websiteUrl || null },
      create: {
        name: entry.name,
        slug,
        market: Market.DE,
        sector: entry.sector,
        websiteUrl: entry.websiteUrl || null,
        isActive: true,
      },
    });

    const existingSource = await prisma.crawlSource.findFirst({
      where: { companyId: company.id, market: Market.DE },
    });

    if (!existingSource) {
      await prisma.crawlSource.create({
        data: {
          companyId: company.id,
          market: Market.DE,
          type: entry.sourceType,
          crawlMethod: CrawlMethod.HTML,
          name: `${entry.name} Stellenangebote`,
          seedUrls: entry.seedUrls || [],
          isActive: true,
        },
      });
      created++;
    } else {
      updated++;
    }
  }

  console.log(`Done! Created: ${created}, Already existed: ${updated}`);
}

main()
  .catch((e) => { console.error(e); process.exit(1); })
  .finally(() => prisma.$disconnect());